def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        boost = 1.0
        decay = 1.0
        complexity = 1.0
        for j in range(1, 15):
            if j % 2 == 0:
                score += (np.tanh(ratio * j) + j*0.1) * (1 + np.cos(j + cap % (j+1)))
                boost *= 1 + 0.02 * j
            else:
                score += (np.exp(-ratio * j) + np.log1p(j)) * (1 - np.sin(j*ratio)) / (j + ratio + 1)
                decay *= (0.98 - 0.005 * j)
            if (cap * j + item) % 11 == 0:
                score *= 1.07
            elif (cap + item * j) % 13 == 0:
                score *= 0.93
            if j % 4 == 3:
                for k in range(1, 4):
                    val = (cap - k * item) / (j + k + 1)
                    if val > 0:
                        penalty += np.sqrt(val) / (k + 2) - np.sin(val / (j + 1))
                    else:
                        penalty -= np.abs(val) ** 1.5 / (k + 3)
            if ratio > 0.7 and j % 5 == 0:
                complexity *= 1.12 + 0.03 * j
            elif ratio < 0.3 and j % 3 == 1:
                complexity *= 0.85 - 0.02 * j
            if (cap + j*j) % 9 == 0:
                penalty += np.cos(ratio * j) * 0.6
            if (item * j - cap) % 8 == 0:
                penalty -= np.sin(j * ratio) * 0.4
        score += penalty * 0.9
        score *= boost * decay * complexity
        if score < 0:
            priorities[i] = -score * (np.log1p(cap * item) + np.sqrt(cap + item))
        else:
            if cap > item * 3:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + ratio * 1.5)
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**1.8)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.1:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        else:
            priorities[i] *= 1.05
        if (cap + item) % 4 == 0:
            priorities[i] *= 1.03
        elif (cap - item) % 5 == 0:
            priorities[i] *= 0.97
    return priorities
